def memory_pool(n, operations):
    slots = [None] * n  # None means free; otherwise [value, next_index]
    free_set = set(range(n))
    head = -1
    tail = -1
    results = []

    for op in operations:
        if op[0] == "alloc":
            value = op[1]
            if not free_set:
                results.append(-1)
            else:
                idx = min(free_set)
                free_set.remove(idx)
                slots[idx] = [value, -1]
                if head == -1:
                    head = idx
                    tail = idx
                else:
                    slots[tail][1] = idx
                    tail = idx
                results.append(idx)
        elif op[0] == "free":
            index = op[1]
            if index < 0 or index >= n or index in free_set:
                results.append(False)
            else:
                free_set.add(index)
                if head == index:
                    head = slots[index][1]
                    if head == -1:
                        tail = -1
                else:
                    prev = head
                    while slots[prev][1] != index:
                        prev = slots[prev][1]
                    slots[prev][1] = slots[index][1]
                    if tail == index:
                        tail = prev
                slots[index] = None
                results.append(True)
        elif op[0] == "read":
            values = []
            cur = head
            while cur != -1:
                values.append(slots[cur][0])
                cur = slots[cur][1]
            results.append(values)

    return results

