import unittest

class TestSolution(unittest.TestCase):
    def test_basic_alloc_and_read(self):
        result = memory_pool(3, [("alloc", 10), ("alloc", 20), ("alloc", 30), ("read",)])
        self.assertEqual(result, [0, 1, 2, [10, 20, 30]])

    def test_alloc_free_realloc(self):
        result = memory_pool(3, [("alloc", 10), ("alloc", 20), ("free", 0), ("alloc", 30), ("read",)])
        self.assertEqual(result, [0, 1, True, 0, [20, 30]])

    def test_full_pool(self):
        result = memory_pool(2, [("alloc", 1), ("alloc", 2), ("alloc", 3)])
        self.assertEqual(result, [0, 1, -1])

    def test_hidden_empty_read(self):
        result = memory_pool(3, [("read",)])
        self.assertEqual(result, [[]])

    def test_hidden_free_invalid(self):
        result = memory_pool(2, [("free", 0), ("free", 5), ("free", -1)])
        self.assertEqual(result, [False, False, False])

    def test_hidden_free_middle_node(self):
        result = memory_pool(4, [("alloc", 10), ("alloc", 20), ("alloc", 30), ("free", 1), ("read",)])
        self.assertEqual(result, [0, 1, 2, True, [10, 30]])

    def test_hidden_reuse_lowest_free(self):
        result = memory_pool(3, [
            ("alloc", 1), ("alloc", 2), ("alloc", 3),
            ("free", 0), ("free", 2),
            ("alloc", 4), ("read",)
        ])
        self.assertEqual(result, [0, 1, 2, True, True, 0, [2, 4]])

    def test_hidden_double_free(self):
        result = memory_pool(2, [("alloc", 5), ("free", 0), ("free", 0)])
        self.assertEqual(result, [0, True, False])

    def test_hidden_free_all_then_alloc(self):
        result = memory_pool(2, [
            ("alloc", 10), ("alloc", 20),
            ("free", 1), ("free", 0),
            ("alloc", 30), ("read",)
        ])
        self.assertEqual(result, [0, 1, True, True, 0, [30]])

    def test_hidden_single_slot_pool(self):
        result = memory_pool(1, [
            ("alloc", 99), ("read",), ("alloc", 100),
            ("free", 0), ("alloc", 42), ("read",)
        ])
        self.assertEqual(result, [0, [99], -1, True, 0, [42]])

if __name__ == '__main__':
    unittest.main()
